"use client";

import { useState, useEffect } from "react";
import { useGetUserBookings } from "@/service/bookings/bookings.queries.js"; // hook for user bookings
import { DataTable } from "@/components";

export default function UserDashboardPage() {
  const userId = localStorage.getItem("userId"); // replace with session/cookie as needed
  const [pagination, setPagination] = useState({ pageIndex: 0, pageSize: 5 });
  const page = pagination.pageIndex + 1;
  const limit = pagination.pageSize;

  const { data, isLoading } = useGetUserBookings({ userId, page, limit });
  const bookings = data?.data ?? [];
  const pageCount = data?.pagination?.totalPages ?? 0;

  const columns = [
    { accessorKey: "id", header: "Booking ID" },
    { accessorKey: "package.name", header: "Package Name" },
    { accessorKey: "package.type", header: "Type" },
    { accessorKey: "bookingDate", header: "Booking Date" },
    { accessorKey: "totalPrice", header: "Price ($)" },
    { accessorKey: "status.name", header: "Status" },
  ];

  return (
    <div className="p-6 min-h-screen bg-slate-100 dark:bg-zinc-900">
      <h1 className="text-3xl font-bold mb-6 text-zinc-800 dark:text-zinc-100">
        My Dashboard
      </h1>

      <div className="bg-white dark:bg-zinc-800 p-4 rounded-xl shadow">
        <DataTable
          columns={columns}
          data={bookings}
          pagination={pagination}
          pageCount={pageCount}
          setPagination={setPagination}
          isLoading={isLoading}
        />
      </div>
    </div>
  );
}
